package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.profile.SupplierAdmissionApplicationService;import com.chaobo.scm.supplier.application.shared.CommandResult;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/supplier/v1/admissions") public class SupplierAdmissionController{private final SupplierAdmissionApplicationService service;private final CommandContextFactory contexts;public SupplierAdmissionController(SupplierAdmissionApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@PostMapping public ApiResponse<CommandResult> create(@Valid @RequestBody Create body,HttpServletRequest request,Authentication auth){return ok(service.create(body.supplierCode(),body.supplierName(),body.taxNo(),body.supplierType(),body.contactName(),body.contactMobile(),body.settlementJson(),contexts.create(request,auth)),request);}@PostMapping("/{id}/submit")public ApiResponse<CommandResult> submit(@PathVariable long id,@Valid @RequestBody Version body,HttpServletRequest request,Authentication auth){return ok(service.submit(id,body.version(),contexts.create(request,auth)),request);}@PostMapping("/{id}/approve")public ApiResponse<CommandResult> approve(@PathVariable long id,@Valid @RequestBody Version body,HttpServletRequest request,Authentication auth){return ok(service.approve(id,body.version(),contexts.create(request,auth)),request);}@PostMapping("/{id}/reject")public ApiResponse<CommandResult> reject(@PathVariable long id,@Valid @RequestBody Reject body,HttpServletRequest request,Authentication auth){return ok(service.reject(id,body.version(),body.reason(),contexts.create(request,auth)),request);}private ApiResponse<CommandResult> ok(CommandResult r,HttpServletRequest q){return ApiResponse.success(r,q.getHeader("X-Request-Id"),q.getHeader("X-Trace-Id"));}public record Create(@NotBlank String supplierCode,@NotBlank String supplierName,@NotBlank String taxNo,@NotBlank String supplierType,@NotBlank String contactName,@NotBlank String contactMobile,@NotBlank String settlementJson){}public record Version(@PositiveOrZero int version){}public record Reject(@PositiveOrZero int version,@NotBlank String reason){}}
